import functools, time

def retry(n):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(n):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == n - 1:
                        raise
                    time.sleep(0.5)
        return wrapper
    return decorator

