from typing import Protocol

class Predictor(Protocol):
    def predict(self, X) -> list: ...

def run_inference(model: Predictor, data):
    return model.predict(data)

# Works without inheriting from Predictor:
class RandomForest:
    def predict(self, X): return [0] * len(X)

# mypy accepts this — RandomForest satisfies Predictor structurally
run_inference(RandomForest(), [[1,2,3]])

