import asyncio

async def task(i):
    if i == 2: raise ValueError('bad')
    return i

async def main():
    results = await asyncio.gather(
        *[task(i) for i in range(5)],
        return_exceptions=True
    )
    for r in results:
        if isinstance(r, Exception):
            print(f'Error: {r}')
        else:
            print(f'OK: {r}')

asyncio.run(main())

import numpy as np

# Slow: Python loop
def clip_loop(arr, lo, hi):
    return [max(lo, min(hi, x)) for x in arr]

# Fast: vectorised
def clip_vec(arr, lo, hi):
    return np.clip(arr, lo, hi)

