-- Missing NULL rows:
SELECT * FROM orders WHERE status != 'cancelled';
-- NULL status rows are excluded!

-- Correct: include NULLs explicitly
SELECT * FROM orders
WHERE status != 'cancelled' OR status IS NULL;

-- Or with COALESCE:
SELECT * FROM orders
WHERE COALESCE(status, '') != 'cancelled';

-- Full table scan without index
SELECT * FROM orders WHERE customer_id = 12345;
-- Seq scan: reads all 100M rows

-- After: CREATE INDEX idx_orders_customer ON orders(customer_id);
-- Index scan: reads log2(100M) ≈ 27 comparisons + row fetch

-- Composite index for multi-column queries
CREATE INDEX idx_orders_date_status ON orders(order_date, status);

-- Slow: function on indexed column defeats index
SELECT * FROM orders WHERE YEAR(order_date) = 2024;

-- Fast: sargable predicate uses index
SELECT order_id, amount FROM orders
WHERE order_date >= '2024-01-01'
  AND order_date <  '2025-01-01';

-- Slow: correlated subquery (executes once per outer row)
SELECT * FROM users u
WHERE (SELECT COUNT(*) FROM orders o WHERE o.user_id = u.id) > 5;

-- Equivalent results and similar performance:
SELECT DISTINCT user_id FROM orders;
SELECT user_id FROM orders GROUP BY user_id;

-- GROUP BY when you need aggregates:
SELECT user_id, COUNT(*) as orders, SUM(amount) as total
FROM orders
GROUP BY user_id
HAVING COUNT(*) > 3;

