-- JSONB column with GIN index
CREATE TABLE events (
    id SERIAL PRIMARY KEY,
    payload JSONB
);
CREATE INDEX idx_events_gin ON events USING GIN (payload);

-- Query inside JSONB
SELECT id, payload->>'user_id' AS user_id
FROM events
WHERE payload @> '{"event_type": "purchase"}';

-- Access nested key
SELECT payload->'metadata'->>'campaign' FROM events;

CREATE TABLE orders (
    id          SERIAL    PRIMARY KEY,          -- PK: unique + not null
    order_ref   VARCHAR   UNIQUE NOT NULL,      -- alternate unique key
    customer_id INTEGER   NOT NULL,
    CONSTRAINT  uq_cust_date UNIQUE (customer_id, order_date)
);

-- Foreign key referencing PK
CREATE TABLE order_items (
    order_id INTEGER REFERENCES orders(id) ON DELETE CASCADE
);

